    return false;
  }
  const counts: Record<string, number> = {};
  for (const ch of s) {
    counts[ch] = (counts[ch] || 0) + 1;
  }
  for (const ch of t) {
    if (!counts[ch]) {
      return false;
    }
    counts[ch] -= 1;
  }
  return true;
}

